#![expect(clippy::same_length_and_capacity, reason = "generated by wit-bindgen")]

wit_bindgen::generate!({
    path: "../../packages/plugin-abi-bench/wit/rich",
    world: "plugin",
});

use exports::lix::abi_bench_rich::api::{DetectedChange, EntityState, File, Guest};

struct RichGuest;

impl Guest for RichGuest {
    fn detect_empty(state: Vec<EntityState>, file: File) -> Result<Vec<DetectedChange>, String> {
        // WIT lifting has already materialized every nested Vec and String by
        // this point. Touch only lengths to keep plugin work negligible.
        std::hint::black_box(state.len().wrapping_add(file.data.len()));
        Ok(Vec::new())
    }

    fn entity_round_trip(
        state: Vec<EntityState>,
        file: File,
    ) -> Result<Vec<DetectedChange>, String> {
        std::hint::black_box(file.data.len());
        Ok(state
            .into_iter()
            .map(|entity| DetectedChange {
                entity_pk: entity.entity_pk,
                schema_key: entity.schema_key,
                snapshot_content: Some(entity.snapshot_content),
                metadata: entity.metadata,
            })
            .collect())
    }

    fn file_round_trip(state: Vec<EntityState>, file: File) -> Result<Vec<u8>, String> {
        std::hint::black_box(state.len());
        Ok(file.data)
    }
}

export!(RichGuest);
